p.m:
\displaystyle{\begin{aligned}
   \left(-\frac{5}{3}\right) \div (-25)
       \amp = \frac{5}{3} \div 25 \\
       \amp = \frac{5}{3} \div \frac{25}{1} \\
       \amp = \frac{5}{3} \cdot \frac{1}{25} \amp \hbox{We can simplify by dividing 5 and 25 by 5, making the numbers smaller.}\\
       \amp = \frac{1}{3}\cdot \frac{1}{5} \\
       \amp = \frac{1 \cdot 1}{3 \cdot 5} \\
       \amp = \frac{1}{15}
\end{aligned}
    }
